#include <stdio.h>
#include <stdlib.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N;
        scanf("%lld", &N);
        if(N % 4 == 1) printf("ALICE\n");
        else printf("BOB\n");
    }
    return 0;
}

