code.Python3:
import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        n = int(data[i])
        out.append('ALICE' if n % 4 == 1 else 'BOB')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

